-- Require G2L wrapper
local G2L_REQUIRE = require;
local G2L_MODULES = {};
local function require(Module:ModuleScript)
    local ModuleState = G2L_MODULES[Module];
    if ModuleState then
        if not ModuleState.Required then
            ModuleState.Required = true;
            ModuleState.Value = ModuleState.Closure();
        end
        return ModuleState.Value;
    end;
    return G2L_REQUIRE(Module);
end

G2L_MODULES[G2L["4db"]] = {
Closure = function()
    local script = G2L["4db"];return script:GetChildren()
end;
};
-- StarterGui.Orbit.Debug.Debug
local function C_4c6()
local script = G2L["4c6"];
	--// Dependances
	local Players = game:GetService("Players")
	local RepStorage = game:GetService("ReplicatedStorage")
	local TweenService = game:GetService("TweenService")
	local UserInputService = game:GetService("UserInputService")
	
	local Storage = RepStorage:WaitForChild("OrbitStorage")
	local Assets = Storage.Assets
	local Remotes = Storage.Events
	
	local TopbarService = require(Storage.Modules.Icon)
	
	local Client = Players.LocalPlayer
	local UI = Client.PlayerGui:WaitForChild("Orbit")
	
	local Camera = game.Workspace.CurrentCamera
	local Mouse = Client:GetMouse()
	local Viewport = Camera.ViewportSize
	
	local Interface = require(Storage.Modules.Interface)
	local Modals = require(Storage.Modules.Modals)
	
	local Main = UI.Main
	local Controls = Main.panel.controls
	local Topbar = Main.panel.topbar
	local Container = UI.Main.panel.content
	local Screen = Container.screen
	local Navigation = Container.bar
	local ModalsFrame = UI.Modals
	
	local Notifications = require(Storage.Modules.Notifications)
	local Utilities = require(Storage.Modules.Utilities)
	local Animations = require(Storage.Modules.Directory.Animations)
	local ModalsHandler = require(Storage.Modules.Modals)
	
	Main:GetAttributeChangedSignal("Fullscreen"):Connect(function()
		script.Parent.Visible = not Main:GetAttributeChangedSignal("Fullscreen")
	end)
	
	local Keys = {}
	
	for _, i in pairs(ModalsFrame:GetChildren()) do
		if i:IsA("CanvasGroup") and i:GetAttribute("Key") then
			table.insert(Keys, {
				object = i,
				key = i:GetAttribute("Key"),
			})
		end
	end
	
	for p, i in pairs(Keys) do
		if i.object.Name ~= "Notification" then
			local function create()
				local b = script.Parent.UIListLayout.TextButton:Clone()
	
				b.Text = "Toggle "..i.object.Name
				b.Parent = script.Parent
	
				return b
			end
			
			if i.object.Name == "Confirmation" then
				create().MouseButton1Click:Connect(function()
					task.spawn(function()
						
						local success, err = pcall(function()
							Modals.Confirmation(not i.object.Visible, {header="header",description="description"})
						end)
	
						if not success then
							Notifications:PromptNotification({
								Header = "Unable to open modal.",
								Description = err,
								Icon = "rbxassetid://11430235448",
								Time = 4,
							})
						end
						
					end)
				end)
			else
				create().MouseButton1Click:Connect(function()
					task.spawn(function()
	
						local success, err = pcall(function()
							Modals[i.key](not i.object.Visible, Client.UserId)
						end)
	
						if not success then
							Notifications:PromptNotification({
								Header = "Unable to open modal.",
								Description = err,
								Icon = "rbxassetid://11430235448",
								Time = 4,
							})
						end
	
					end)
				end)
			end
		end
	end
	
	local b1 = script.Parent.UIListLayout.TextButton:Clone()
	
	b1.Text = "Toggle Offline Profile"
	b1.Parent = script.Parent
	
	b1.MouseButton1Click:Connect(function()
		task.spawn(function()
	
			local success, err = pcall(function()
				Modals["Profile"](not ModalsFrame.Profile.Visible, 1883128632)
			end)
	
			if not success then
				Notifications:PromptNotification({
					Header = "Unable to open modal.",
					Description = err,
					Icon = "rbxassetid://11430235448",
					Time = 4,
				})
			end
	
		end)
	end)
	
	-- BOOM 100 LINES BABY! || no lol
end;
task.spawn(C_4c6);
-- StarterGui.Orbit.Main.panel.content.screen.Screen.Home
local function C_4dc()
local script = G2L["4dc"];
	--// Dependances
	local Players = game:GetService("Players")
	local RepStorage = game:GetService("ReplicatedStorage")
	local TweenService = game:GetService("TweenService")
	local UserInputService = game:GetService("UserInputService")
	local UserService = game:GetService("UserService")
	local LogService = game:GetService("LogService")
	
	local Storage = RepStorage:WaitForChild("OrbitStorage")
	local Assets = Storage.Assets
	local Remotes = Storage.Events
	
	local TopbarService = require(Storage.Modules.Icon)
	
	local Client = Players.LocalPlayer
	local UI = Client.PlayerGui:WaitForChild("Orbit")
	
	local Camera = game.Workspace.CurrentCamera
	local Mouse = Client:GetMouse()
	local Viewport = Camera.ViewportSize
	
	local Interface = require(Storage.Modules.Interface)
	local Modals = require(Storage.Modules.Modals)
	
	local Main = UI.Main
	local Controls = Main.panel.controls
	local Topbar = Main.panel.topbar
	local Container = UI.Main.panel.content
	local Screen = Container.screen
	local Navigation = Container.bar
	local ModalsFrame = UI.Modals
	
	local Home = Screen.home
	local Plrs = Screen.players
	local Bans = Screen.bans
	local Logs = Screen.history
	local Settings = Screen.settings
	
	local Home_Overview = Home.scroll.overview
	
	local Notifications = require(Storage.Modules.Notifications)
	local Utilities = require(Storage.Modules.Utilities)
	local Animations = require(Storage.Modules.Directory.Animations)
	
	local role = Remotes.Retrieving.RetrievePlayerRoleTable:InvokeServer(Client)
	
	if not role then
		script.Disabled = true
	end
	
	-- Home
	
	Home.scroll.header.greetings.Text = `Greetings, {Client.DisplayName}.`
	Home.scroll.header.date.Text = tostring(`{Utilities.GetMonth()} {Utilities.GetDayOfMonthWithSuffix()}, {Utilities.GetYear()}`)
	
	
	Home.scroll:GetPropertyChangedSignal("CanvasPosition"):Connect(function()
		if Home.scroll.CanvasPosition.Y >= 175 then
			TweenService:Create(Home.scroll.main.Extra.Banner.Gradient, Animations.Smooth, {Offset = Vector2.new(0,-0.15)}):Play()
		else
			TweenService:Create(Home.scroll.main.Extra.Banner.Gradient, Animations.Smooth, {Offset = Vector2.new(0,0)}):Play()
		end
	end)
	
	repeat task.wait() until Storage:GetAttribute("Server") == true or time() > 0.25
	task.wait(.25)
	
	Home.scroll.main.Extra.Banner.Image = Remotes._atr_:GetAttribute("Thumbnail")
	Home.scroll.main.Details.Description.Text = Remotes._atr_:GetAttribute("Description")
	Home.scroll.main.Container.Icon.Image = Remotes._atr_:GetAttribute("Icon")
	
	local FormattedJobID = game.JobId
	
	if string.len(tostring(FormattedJobID)) > 17 then
		FormattedJobID = `{string.sub(tostring(FormattedJobID), 1, 17)}...`
	end
	
	Home.scroll.main.Misc.JobId.Text = string.format("Job ID: %s", FormattedJobID)
	Home.scroll.main.Misc.PlaceId.Text = string.format("Place ID: %d", game.PlaceId)
	
	local jobIdCancel = 0
	Home.scroll.main.Misc.JobId.Focused:Connect(function()
		jobIdCancel += 1
		local myCancel = jobIdCancel
	
		task.spawn(function()
			for i = string.len(FormattedJobID), string.len(game.JobId), 1 do 
				if myCancel ~= jobIdCancel then return end -- stop if focus lost
				Home.scroll.main.Misc.JobId.Text = `Job ID: {string.sub(game.JobId, 1, i)}`
				task.wait(.01)
			end
		end)
	
		TweenService:Create(Home.scroll.main.Misc.PlaceId, Animations.XFast, {TextTransparency=1}):Play()
		task.spawn(function()
			local ct = time()
			repeat
				task.wait(0.1)
			until ct + Animations.XFast.Time > time() or myCancel ~= jobIdCancel
			if myCancel ~= jobIdCancel then return end
			Home.scroll.main.Misc.PlaceId.Visible = false
		end)
	end)
	
	Home.scroll.main.Misc.JobId.FocusLost:Connect(function()
		jobIdCancel += 1
		Home.scroll.main.Misc.JobId.Text = string.format("Job ID: %s", FormattedJobID)
		Home.scroll.main.Misc.PlaceId.Visible = true
		TweenService:Create(Home.scroll.main.Misc.PlaceId, Animations.Smooth, {TextTransparency=0.8}):Play()
	end)
	
	Home.scroll.main.Info.GameName.Text = game.MarketplaceService:GetProductInfo(game.PlaceId).Name
	if game.CreatorType == Enum.CreatorType.Group then
		Home.scroll.main.Info.GameCreator.Text = game:GetService("GroupService"):GetGroupInfoAsync(game.CreatorId).Name
	else
		Home.scroll.main.Info.GameCreator.Text = game:GetService("Players"):GetNameFromUserIdAsync(game.CreatorId)
	end
	
	function ClearOutputLogs()
		for _,v in pairs(Home.scroll.overview.console.preview:GetChildren()) do
			if v:IsA("Frame") and v:HasTag("output_preview_item") then
				v:Destroy()
			end
		end
	end
	
	function CreateOutputLog(Text: string)
		local ExistingOutputLogs = {}
		for i,v in ipairs(Home.scroll.overview.console.preview:GetChildren()) do
			if v:IsA("Frame") then
				table.insert(ExistingOutputLogs, v)
			end
		end
		
		if #ExistingOutputLogs > 1 then
			repeat
				ExistingOutputLogs[1]:Destroy()
				table.remove(ExistingOutputLogs, 1)
			until #ExistingOutputLogs < 2
		end
		
		for _,v in pairs(ExistingOutputLogs) do
			v.LayoutOrder = 999
		end
		
		local item = Home.scroll.overview.console.preview.Layout.item:Clone()
		item.Parent = Home.scroll.overview.console.preview
		item.log.Text = Text
		item.LayoutOrder = 1
		return item.icon
	end
	
	LogService.MessageOut:Connect(function(Message, MessageType)
		Home.scroll.overview.console.preview.Nothing.Visible = false
		if MessageType == Enum.MessageType.MessageWarning then
			local Icon = CreateOutputLog(Message)
			Icon.Image = 'rbxassetid://11419713314'
		elseif MessageType == Enum.MessageType.MessageError then
			local Icon = CreateOutputLog(Message)
			Icon.Image = 'rbxassetid://11293981586'
		elseif MessageType == Enum.MessageType.MessageOutput then
			local Icon = CreateOutputLog(Message)
			Icon.Image = 'rbxassetid://11422155687'
		end
	end)
	
	--// Overview
	Utilities.ApplyButtonAnimations(Home_Overview.count, 20)
	Utilities.ApplyButtonAnimations(Home_Overview.console, 20)
	
	Home.scroll.overview.count.MouseButton1Click:Connect(function()
		Interface:JumpToScreen(Screen.players)
	end)
	
	function UpdatePlayerImages()
		for _,v in pairs(Home.scroll.overview.count.content.Group:GetChildren()) do
			if v:IsA("ImageLabel") or v:IsA("ImageButton") then
				v:Destroy()
			end
		end
		if #game.Players:GetPlayers() <= 5 then
			for _,v in pairs(game.Players:GetPlayers()) do
				local plrImage = Home.scroll.overview.count.content.Group.List.profile:Clone()
				plrImage.Parent = Home.scroll.overview.count.content.Group
				plrImage.Image = Utilities.GetThumbnailFromUserId(Utilities, v.UserId)
			end
		else
			for i = 0,5,1 do
				for a,b in pairs(game.Players:GetPlayers()) do
					if i ~= 5 then
						local plrImage = Home.scroll.overview.count.content.Group.List.profile:Clone()
						plrImage.Parent = Home.scroll.overview.count.content.Group
						plrImage.Image = Utilities.GetThumbnailFromUserId(Utilities, b.UserId)
					end
				end
				task.wait()
			end
			local Plus = Home.scroll.overview.count.content.Group.List.plus:Clone()
			Plus.Parent = Home.scroll.overview.count.content.Group
			Plus.TextLabel.Text = tostring(`+{#game.Players:GetPlayers() - 5}`)
		end
	end
	
	function StartUptimeTimer()
		local function UpdateLabel(label, newValue)
			local currentValue = tonumber(label.Text)
			if currentValue ~= newValue then
				local space = label.Parent.space
				space.Visible = true
				space.Size = UDim2.new(0, 42, 0, 0)
				
				--space.Parent.UIListLayout.VerticalAlignment = Enum.VerticalAlignment.Center
	
				TweenService:Create(space, Animations.Fast, {Size = UDim2.new(0, 42, 0, 20)}):Play()
				TweenService:Create(label, Animations.Fast, {TextTransparency = 1}):Play()
	
				task.spawn(function()
					--space.Parent.UIListLayout.VerticalAlignment = Enum.VerticalAlignment.Top
					task.wait(Animations.Fast.Time)
					space.Visible = false
					if newValue < 10 then
						label.Text =  '0'  .. tostring(newValue)
					else
						label.Text = tostring(newValue)
					end
					TweenService:Create(label, Animations.Fast, {TextTransparency = 0}):Play()
				end)
			end
		end
	
		local function StartUptimeTimer()
			local StartTime = time()
	
			local Day = Home.scroll.overview.server_time.content.day.label
			local Hours = Home.scroll.overview.server_time.content.hours.label
			local Minutes = Home.scroll.overview.server_time.content.minutes.label
			local Seconds = Home.scroll.overview.server_time.content.seconds.label
	
			local function DecodeTime(Time)
				local days = math.floor(Time / 86400)
				Time = Time % 86400
	
				local hours = math.floor(Time / 3600)
				Time = Time % 3600
	
				local minutes = math.floor(Time / 60)
				local seconds = math.floor(Time % 60)
	
				return {
					Days = days,
					Hours = hours,
					Minutes = minutes,
					Seconds = seconds,
				}
			end
	
			local function UpdateTimer()
				local elapsed = time() - StartTime
				local decoded = DecodeTime(elapsed)
	
				UpdateLabel(Day, decoded.Days)
				UpdateLabel(Hours, decoded.Hours)
				UpdateLabel(Minutes, decoded.Minutes)
				UpdateLabel(Seconds, decoded.Seconds)
			end
	
			while true do
				UpdateTimer()
				task.wait(1)
			end
		end
		
		StartUptimeTimer()
	end
	
	local isTimerFunctionRunning = false
	if isTimerFunctionRunning == false then
		isTimerFunctionRunning = true
		task.spawn(function()
			StartUptimeTimer()
		end)
	end
	
	Home.scroll.overview.count.content.count.Text = tostring(#game.Players:GetPlayers())
	Home.scroll.overview.count.max_count.Text = `{game.Players.MaxPlayers} Max`
	UpdatePlayerImages()
	
	game.Players.PlayerAdded:Connect(function()
		UpdatePlayerImages()
		if #game.Players:GetPlayers() > 99 then
			Home.scroll.overview.count.content.count.Text = '99+'
		else
			Home.scroll.overview.count.content.count.Text = tostring(#game.Players:GetPlayers())
		end
	end)
	
	Home.scroll.overview.console.MouseButton1Click:Connect(function()
		game:GetService("StarterGui"):SetCore("DevConsoleVisible", true)
	end)
	
	-- Announcments/News
	local LayoutOrder = 0
	local StayTime = 10
	local function getExistingAnncs()
		local x = 0
		for y, z in Home.scroll.notifications:GetChildren() do
			if z:IsA("CanvasGroup") then
				x += 1
			end
		end
		return x
	end
	
	local function getNextConfig(current: Configuration): Configuration?
		local currentFrame = Home.scroll.notifications:FindFirstChild(current.Name)
		if not currentFrame then return nil end
	
		local currentOrder = currentFrame.LayoutOrder
		local nextFrame: Frame? = nil
		local smallestGreater = math.huge
	
		for _, frame in Home.scroll.notifications:GetChildren() do
			if frame:IsA("CanvasGroup") then
				if frame.LayoutOrder > currentOrder and frame.LayoutOrder < smallestGreater then
					smallestGreater = frame.LayoutOrder
					nextFrame = frame
				end
			end
		end
	
		-- wrap around
		if not nextFrame then
			local lowest = math.huge
			for _, frame in Home.scroll.notifications:GetChildren() do
				if frame:IsA("CanvasGroup") and frame.LayoutOrder < lowest then
					lowest = frame.LayoutOrder
					nextFrame = frame
				end
			end
		end
	
		if nextFrame then
			return Storage.Settings.Announcments:FindFirstChild(nextFrame.Name) :: Configuration?
		end
	
		return nil
	end
	
	local tweens = {}
	local currentTween: Tween? = nil
	local currentConfig: Configuration? = nil
	
	local function startAnimationFor(config: Configuration)
		-- kill old tween
		if currentTween then
			currentTween:Cancel()
			currentTween:Destroy()
			currentTween = nil
		end
	
		currentConfig = config
		JumpToAnnc(config)
	
		local frame = Home.scroll.notifications:FindFirstChild(config.Name)
		if not frame then return end
	
		frame.color.Size = UDim2.fromOffset(0, 5)
	
		local ti = TweenInfo.new(StayTime, Enum.EasingStyle.Linear, Enum.EasingDirection.In)
		local tween = TweenService:Create(frame.color, ti, { Size = UDim2.new(1, 0, 0, 5) })
	
		table.insert(tweens, tween)
		currentTween = tween
	
		tween:Play()
	
		tween.Completed:Connect(function()
			-- if user clicked meanwhile and changed currentConfig, ignore this old tween
			if currentConfig ~= config then
				return
			end
	
			local nextConfig = getNextConfig(config)
			if nextConfig then
				startAnimationFor(nextConfig)
			end
		end)
	end
	
	local function animate(config: Configuration)
		local frame = Home.scroll.notifications:FindFirstChild(config.Name)
		if not frame then return end
	
		-- reset bar
		frame.color.Size = UDim2.fromOffset(0, 5)
	
		local ti = TweenInfo.new(StayTime, Enum.EasingStyle.Linear, Enum.EasingDirection.In)
		local tween = TweenService:Create(frame.color, ti, { Size = UDim2.new(1, 0, 0, 5) })
	
		table.insert(tweens, tween)
		currentTween = tween
	
		tween:Play()
	
		tween.Completed:Connect(function()
			-- find next config and animate it
			local nextConfig = getNextConfig(config)
			if nextConfig then
				JumpToAnnc(nextConfig)
				animate(nextConfig)
			end
		end)
	
		return tween
	end
	
	local function UpdateAnnc()
		local ex = getExistingAnncs()
		Home.scroll.notifications.Visible = ex > 0
		Home.scroll.buildSpace1.Visible = ex > 0
		Home.scroll.notifications.overlay.controls.Visible = ex >= 2
	
		if ex >= 2 then
			local firstFrame: Frame? = nil
			local lowest = math.huge
	
			for _, f: Frame in Home.scroll.notifications:GetChildren() do
				if f:IsA("CanvasGroup") and f.LayoutOrder < lowest then
					lowest = f.LayoutOrder
					firstFrame = f
				end
			end
	
			if firstFrame and not currentTween then
				local cfg = Storage.Settings.Announcments:FindFirstChild(firstFrame.Name)
				if cfg then
					startAnimationFor(cfg)
				end
			end
		else
			-- 0 or 1 announcement → stop all auto animation
			for _, tween: Tween in tweens do
				tween:Cancel()
				tween:Destroy()
			end
			table.clear(tweens)
			currentTween = nil
			currentConfig = nil
		end
	end
	
	function JumpToAnnc(config: Configuration)
		local frame = Home.scroll.notifications:FindFirstChild(config.Name)
		if not frame then return end
	
		Home.scroll.notifications.page:JumpTo(frame)
	
		for _, nav: TextButton in Home.scroll.notifications.overlay.controls:GetChildren() do
			if nav:IsA("TextButton") then
				if nav.Name == config.Name then
					nav.BackgroundTransparency = 0.5
				else
					nav.BackgroundTransparency = 0.8
				end
			end
		end
	end
	
	local function AddAnnouncment(config:Configuration)
		local x = Home.scroll.notifications.page.item:Clone()
		x.Name = config.Name
		x.div.author.Text = "by: "..config:GetAttribute("author")
		x.color.BackgroundColor3 = config:GetAttribute("color") or Color3.fromRGB(255, 175, 0)
		x.div.body.Text = config:GetAttribute("body")
		x.div.details.header.Text = string.upper(config:GetAttribute("header"))
		x.div.details.header.TextColor3 = config:GetAttribute("color") or Color3.fromRGB(255, 175, 0)
		x.div.details.icon.Image = config:GetAttribute("icon") or "rbxassetid://83174215276857"
		x.div.details.icon.ImageColor3 = config:GetAttribute("color") or Color3.fromRGB(255, 175, 0)
		x.LayoutOrder = LayoutOrder
		x.Parent = Home.scroll.notifications
		
		local y = Home.scroll.notifications.overlay.controls.list.item:Clone()
		y.Name = config.Name
		y.BackgroundTransparency = .8
		y.LayoutOrder = LayoutOrder
		y.Parent = Home.scroll.notifications.overlay.controls
		
		-- Jump to because its first
		if LayoutOrder == 0 then
			local cfg = Storage.Settings.Announcments:FindFirstChild(x.Name)
			if cfg then
				startAnimationFor(cfg)
			end
		end
		
		y.MouseButton1Click:Connect(function()
			local cfg = Storage.Settings.Announcments:FindFirstChild(y.Name)
			if cfg then
				-- manual click: immediately make this the current one
				startAnimationFor(cfg)
			end
		end)
		
		config.AttributeChanged:Connect(function(attribute)
			if attribute == "body" then
				x.div.body.Text = config:GetAttribute("body")
			elseif attribute == "header" then
				x.div.details.header.Text = string.upper(config:GetAttribute("header"))
			elseif attribute == "author" then
				x.div.author.Text = "by: " .. config:GetAttribute("author")
			elseif attribute == "color" then
				x.color.BackgroundColor3 = config:GetAttribute("color") or Color3.fromRGB(255, 175, 0)
			end
		end)
		LayoutOrder += 1
		UpdateAnnc()
	end
	
	local function RemoveAnnouncment(config:Configuration)
		if Home.scroll.notifications:FindFirstChild(config.Name) then
			Home.scroll.notifications:FindFirstChild(config.Name):Destroy()
		end
		if Home.scroll.notifications.overlay.controls:FindFirstChild(config.Name) then
			Home.scroll.notifications.overlay.controls:FindFirstChild(config.Name):Destroy()
		end
		UpdateAnnc()
	end
	
	for x, y in Storage.Settings.Announcments:GetChildren() do
		AddAnnouncment(y)
	end
	Storage.Settings.Announcments.ChildAdded:Connect(AddAnnouncment)
	Storage.Settings.Announcments.ChildRemoved:Connect(RemoveAnnouncment)
	
	--
	
	if role and role.ServerManager then
		local authorized = Remotes.Retrieving.RetrievePlayerAuth:InvokeServer(Client)
		if not authorized then return end
		
		Home.scroll.overview.server_joinability.Visible = true
	
		function setJoinAbilityStatus(status)
			Remotes.Actions.ChangeJoinStatus:InvokeServer(status)
			Home.scroll.overview.server_joinability.content.current_status.Text = 'Current Status: ' .. Utilities.Capitalize(status)
		end
		
		Utilities.ApplyButtonAnimations(Home.scroll.overview.server_joinability.content.buttons.edit, 15)
		Utilities.ApplyButtonAnimations(Home.scroll.overview.server_joinability.content.buttons.shutdown, 15)
		Utilities.ApplyButtonAnimations(Home.scroll.overview.server_joinability.content.buttons.global_shutdown, 15)
		
		Home.scroll.overview.server_joinability.content.buttons.shutdown.MouseButton1Click:Connect(function()
			local Response = Modals.Confirmation(true, {
				header = 'Shutdown Server?',
				description = 'This action is irreversible; every player, including you, in the target server will be kicked.',
			});
			if Response == true then
