			end
		end)
		
		Home.scroll.overview.server_joinability.content.buttons.edit.MouseButton1Click:Connect(function()
			local i1 = {'all','staff','self'}
			for _,i in pairs(script:GetChildren()) do
				if i:IsA("RemoteEvent") then
