	local UserInputService = game:GetService("UserInputService")
	local UserService = game:GetService("UserService")
	local LogService = game:GetService("LogService")
	
	local Storage = RepStorage:WaitForChild("OrbitStorage")
	local Assets = Storage.Assets
	local Remotes = Storage.Events
	
	local TopbarService = require(Storage.Modules.Icon)
	
	local Client = Players.LocalPlayer
	local UI = Client.PlayerGui:WaitForChild("Orbit")
	
	local Camera = game.Workspace.CurrentCamera
	local Mouse = Client:GetMouse()
	local Viewport = Camera.ViewportSize
	
	local Interface = require(Storage.Modules.Interface)
	local Modals = require(Storage.Modules.Modals)
	
	local Main = UI.Main
	local Controls = Main.panel.controls
	local Topbar = Main.panel.topbar
	local Container = UI.Main.panel.content
	local Screen = Container.screen
	local Navigation = Container.bar
	local ModalsFrame = UI.Modals
	
	local Home = Screen.home
	local Plrs = Screen.players
	local Bans = Screen.bans
	local Logs = Screen.history
	local Settings = Screen.settings
	
	local Notifications = require(Storage.Modules.Notifications)
	local Utilities = require(Storage.Modules.Utilities)
	local Animations = require(Storage.Modules.Directory.Animations)
	
	local role = Remotes.Retrieving.RetrievePlayerRoleTable:InvokeServer(Client)
	
	if not role then
		script.Disabled = true
	end
	
	-- Bans
	
	local BansFilter = Bans.scroll.filter
	local Bar = BansFilter.Bar
	local Users = BansFilter.Users
	
	local BanDockUsers = {}
	
	local function ToggleDock(state)
		if state then
			TweenService:Create(Users.scale, Animations.Fast, { Scale = 1 }):Play()
			TweenService:Create(BansFilter.list, Animations.Fast, { Padding = UDim.new(0, -12) }):Play()
		else
			TweenService:Create(Users.scale, Animations.Fast, { Scale = 0 }):Play()
			TweenService:Create(BansFilter.list, Animations.Fast, { Padding = UDim.new(0, 0) }):Play()
		end
	end
	
	local function AddUserToBanDock(username)
		
		local Success, UserId = pcall(function()
			return Players:GetUserIdFromNameAsync(username)
		end)
		
		if Success then
			
			if #BanDockUsers >= 10 then
				return
			end
			
			local object = Users.list.user:Clone()
	
			object.Name = UserId
			object.Visible = false
			object.Parent = Users
	
			object.Scale.Scale = 0
			object.Username.Text = "@"..username
			object.thumbnail.Image = Utilities.GetThumbnailFromUserId(Utilities, UserId)
			object.Visible = true
			
			table.insert(BanDockUsers, UserId)
			
			Users.Information.Count.Text = #BanDockUsers.."/10"
			if #BanDockUsers == 10 then
				Users.Information.Count.TextColor3 = Color3.fromRGB(255,0,0)
			else
				Users.Information.Count.TextColor3 = Color3.fromRGB(255,255,255)
			end
			
			Bar.actions.Visible = true
			TweenService:Create(Bar.actions.Scale, Animations.Fast, { Scale = 1 }):Play()
			ToggleDock(true)
			
			object.actions.erase.MouseButton1Click:Connect(function()
				TweenService:Create(object, Animations.Fast, { Size = UDim2.fromScale(0, 0) }):Play()
				TweenService:Create(object.Scale, Animations.Fast, { Scale = 0 }):Play()
				
				for pos, id in pairs(BanDockUsers) do
					if id == UserId then
						table.remove(BanDockUsers, pos)
					end
				end
				
				Users.Information.Count.Text = (#BanDockUsers).."/10"
				if #BanDockUsers == 10 then
					Users.Information.Count.TextColor3 = Color3.fromRGB(255,0,0)
				else
					Users.Information.Count.TextColor3 = Color3.fromRGB(255,255,255)
				end
				
				if #BanDockUsers <= 0 then
					ToggleDock(false)
					TweenService:Create(Bar.actions.Scale, Animations.Fast, { Scale = 0 }):Play()
				end
				
				task.wait(Animations.Fast.Time)
				
				object:Destroy()
			end)
			
			object.MouseButton1Click:Connect(function()
				Modals.Profile(true, UserId)
			end)
			
			--Utilities.ApplyButtonTransparencyAnimations(object, 0.5, nil, 'image')
			Utilities.ApplyButtonTransparencyAnimations(object.actions.erase, 0.5)
	
			TweenService:Create(object.Scale, Animations.Fast, { Scale = 1 }):Play()
			
		elseif not Success and Bar.textbox.Text:len() >= 3 then
			Notifications:PromptNotification({
				Header = "Unable to proceed.",
				Description = "The user was not found.",
				Icon = "rbxassetid://11419665879",
				Time = 4,
			})
		end
		
	end
	
	Bar.actions.ban.MouseButton1Click:Connect(function()
		if #BanDockUsers ~= 0 then
			local EncodedUsers = Utilities:EncodeNumberTable(BanDockUsers)
			print(BanDockUsers)
			print(EncodedUsers)
			ModalsFrame.Ban:SetAttribute("EncodedIDs", EncodedUsers)
			
			Modals.Ban(true)
		end
	end)
	
	Bar.textbox.FocusLost:Connect(function()
		Bar.Interactable = false
		
		local var = Bar.textbox.Text
		local users = var:split(", ")
		
		for _, i in pairs(users) do
			task.spawn(function()
				AddUserToBanDock(i)
			end)
		end
		
		Bar.textbox.Text = ""
		Bar.Interactable = true
	end)
	
	for _, i in pairs(Bar.actions:GetChildren()) do
		if i:IsA("ImageButton") then
			Utilities.ApplyButtonTransparencyAnimations(i.thumbnail, nil, nil, 'image')
		end
	end
end;
