local function C_4df()
local script = G2L["4df"];
	--// Dependances
	local Players = game:GetService("Players")
	local RepStorage = game:GetService("ReplicatedStorage")
	local TweenService = game:GetService("TweenService")
	local UserInputService = game:GetService("UserInputService")
	local UserService = game:GetService("UserService")
	local LogService = game:GetService("LogService")
	
	local Storage = RepStorage:WaitForChild("OrbitStorage")
	local Assets = Storage.Assets
	local Remotes = Storage.Events
	
	local TopbarService = require(Storage.Modules.Icon)
	
	local Client = Players.LocalPlayer
	local UI = Client.PlayerGui:WaitForChild("Orbit")
	
	local Camera = game.Workspace.CurrentCamera
	local Mouse = Client:GetMouse()
	local Viewport = Camera.ViewportSize
	
	local Interface = require(Storage.Modules.Interface)
	local Modals = require(Storage.Modules.Modals)
	
	local Main = UI.Main
	local Controls = Main.panel.controls
	local Topbar = Main.panel.topbar
	local Container = UI.Main.panel.content
	local Screen = Container.screen
	local Navigation = Container.bar
	local ModalsFrame = UI.Modals
	
	local Home = Screen.home
	local Plrs = Screen.players
	local Bans = Screen.bans
	local Logs = Screen.history
	local Settings = Screen.settings
	local History = Screen.history
	
	local Notifications = require(Storage.Modules.Notifications)
	local Utilities = require(Storage.Modules.Utilities)
	local Animations = require(Storage.Modules.Directory.Animations)
	
	local role = Remotes.Retrieving.RetrievePlayerRoleTable:InvokeServer(Client)
	
	if not role then
		script.Disabled = true
	end
	
	--// Utility Helpers
	
	function Janitor()
		for _, i in pairs(History.scroll.display.scroll:GetChildren()) do
			if i:IsA("ImageButton") and i:HasTag("HistoryLog") then
				i:Destroy()
			end
		end
	end
	
	function GetLogName(User : Player)
		local count = 1
		
		for _, i in pairs(History.scroll.display.scroll:GetChildren()) do
			if i:IsA("ImageButton") and i:HasTag("HistoryLog") then
				if i.Name:find(User.Name) then
					count += 1
				end
			end
		end
		
		return string.format("%s_%d", User.Name, count)
	end
	
	function CreateLog(User : Player, Command : string, Time : string)
		if (User and Command and Time) then
			local NewLog = History.scroll.display.scroll.List.item:Clone()
			
			NewLog.Size = UDim2.new(0, 0, 0, 65)
			
			local FormattedName = string.format("@%s", User.Name)
			local LogName = GetLogName(User)
			local ThumbnailID = Utilities:GetThumbnailFromUserId(User.UserId)
			
			NewLog.Information.Header.Text = string.format("%s was called!", Command)
			NewLog.Information.Information.Text = string.format("%s | %s", FormattedName, Time)
			
			NewLog.Icon.Image = ThumbnailID or "rbxassetid://11419714821"
			NewLog.Name = FormattedName
			NewLog.Parent = Screen.history.scroll.display.scroll
			
			NewLog:AddTag("HistoryLog")
			
			Utilities.ApplyButtonAnimations(NewLog.Actions.Delete, 2)
			Utilities.ApplyButtonTransparencyAnimations(NewLog.Actions, 0.25)
			
			NewLog.Actions.Delete.Activated:Connect(function()
				Remotes.UI.DeleteLog:FireServer(NewLog.Name)
			end)
			
			TweenService:Create(NewLog, Animations.Smooth, { Size = UDim2.new(1, 5, 0, 65) }):Play()
		end
	end
	
	
	--// Remote Listener
	
	Remotes.UI.NewLog.OnClientEvent:Connect(function(Data)
		if Data then
			local User = Data.User
			local Command = Data.Command
			local Time = Data.Time
			
			local Authorized = Remotes.Retrieving.RetrievePlayerAuth:InvokeServer(User)
			
			if Authorized then
				CreateLog(User, Command, Time)
			end
		end
	end)
	
	Remotes.UI.DeleteLog.OnClientEvent:Connect(function(Name)
		if Screen.history.scroll.display.scroll:FindFirstChild(Name) then
			Screen.history.scroll.display.scroll:FindFirstChild(Name):Destroy()
		end
	end)
	
	--// Initialize
	
	Janitor()
end;
