	Widgets.scroll.filter.search.textbox:GetPropertyChangedSignal("Text"):Connect(function()
		for x,y in pairs(Widgets.scroll:GetChildren()) do
			if y:IsA("CanvasGroup") then
				if string.find(string.lower(y.Name), string.lower(Widgets.scroll.filter.search.textbox.Text)) then
