				else
					y.Visible = false
				end
			end
		end
	end)
	
	function RegisterWidgets()
		local RegisteredWidgets = WidgetsModule.GetWidgets()
		
		Janitor();
		for x,y in pairs(RegisteredWidgets) do
			local Template = Widgets.scroll.Layout.template:Clone()
			Template.Parent = Widgets.scroll
			
			Template.container.holder.icon.Image = y.Icon
			Template.container.info.Header.Text = y.DisplayName
			Template.container.info.Description.Text = y.DisplayDescription
			Template.LayoutOrder = y.LayoutOrder
			Template.Name = y.Name
			
			Template.container.open.MouseButton1Click:Connect(function()
