				Modals[y.ModalKey](true)
				Modals.setupLeaderstatsEditor(Client)
				
				if Template.Name == 'Tools' then
					Modals.Tools(true)
				end
			end)
		end
	end
	
	function Constant()
		local regi_num = 0
		while task.wait(.5) do
			local RegisteredWidgets = WidgetsModule.GetWidgets()
			if #RegisteredWidgets ~= regi_num then
				RegisterWidgets()
				regi_num = #RegisteredWidgets
			end
