local function C_4e1()
local script = G2L["4e1"];
	--// Dependances
	local Players = game:GetService("Players")
	local RepStorage = game:GetService("ReplicatedStorage")
	local TweenService = game:GetService("TweenService")
	local UserInputService = game:GetService("UserInputService")
	local UserService = game:GetService("UserService")
	local LogService = game:GetService("LogService")
	
	local Storage = RepStorage:WaitForChild("OrbitStorage")
	local Assets = Storage.Assets
	local Remotes = Storage.Events
	
	local TopbarService = require(Storage.Modules.Icon)
	
	local Client = Players.LocalPlayer
	local UI = Client.PlayerGui:WaitForChild("Orbit")
	
	local Camera = game.Workspace.CurrentCamera
	local Mouse = Client:GetMouse()
	local Viewport = Camera.ViewportSize
	
	local Interface = require(Storage.Modules.Interface)
	local Modals = require(Storage.Modules.Modals)
	
	local Main = UI.Main
	local Controls = Main.panel.controls
	local Topbar = Main.panel.topbar
	local Container = UI.Main.panel.content
	local Screen = Container.screen
	local Navigation = Container.bar
	local ModalsFrame = UI.Modals
	
	local Home = Screen.home
	local Plrs = Screen.players
	local Bans = Screen.bans
	local Logs = Screen.history
	local Settings = Screen.settings
	
	local Notifications = require(Storage.Modules.Notifications)
	local Utilities = require(Storage.Modules.Utilities)
	local Animations = require(Storage.Modules.Directory.Animations)
	
	local role = Remotes.Retrieving.RetrievePlayerRoleTable:InvokeServer(Client)
	
	if not role then
		script.Disabled = true
	end
	
	-- Players
	
	local CurrentOrder = 0
	
	function AddPlayer(Plr: Player)
		
		local Item = Plrs.scroll.display.scroll.List.item:Clone()
	
		Item.Name = Plr.UserId
		Item.Parent = Plrs.scroll.display.scroll
		Item.Size = UDim2.new(0, 0, 0, 65)
		Item.Interactable = false
		
		local isClient = Plr.UserId == Client.UserId
		
		local display = Plr.DisplayName
		
		if isClient then
			display = Plr.DisplayName.." (You)"
			Item.LayoutOrder = -9999999
		else
			Item.LayoutOrder = CurrentOrder
			CurrentOrder += 1
			pcall(function()
				if game.Players:GetUserIdFromNameAsync(Plrs.scroll.filter.offline.textbox.Text) then
					Item.LayoutOrder = -1
				end
			end)
		end
		
		if Remotes.Retrieving.RetrievePlayerAuth:InvokeServer(Plr) == true then
			Item.Tag.Visible = true
			Item.Tag.Text = Remotes.Retrieving.RetrievePlayerRole:InvokeServer(Plr) or 'Member'
			if Remotes.Retrieving.RetrievePlayerRole:InvokeServer(Plr) == nil then
				Item.Tag.BackgroundColor3 = Color3.fromRGB(0,0,0)
			else
				Item.Tag.BackgroundColor3 = Remotes.Retrieving.RetrievePlayerRoleTable:InvokeServer(Plr).Color
			end
		end
		
		Item.Information.Username.Text = "@"..Plr.Name
		Item.Information.Display.Text = display
		Item.Thumbnail.Image = Utilities.GetThumbnailFromUserId(Utilities, Plr.UserId)
		
		Item.MouseButton1Click:Connect(function()
			Modals.Profile(true, Plr.UserId)
		end)
		
		Item:SetAttribute("UserId", Plr.UserId)
		
		Utilities.ApplyButtonAnimations(Item, 2)
		Utilities.ApplyButtonTransparencyAnimations(Item, 0.25)
	
		for _ , i in pairs(Item.Actions:GetChildren()) do
			if i:HasTag("OrbitProfileFastAction") and i:IsA("ImageButton") then
				
				if i.Name == 'Kick' then
					if not game.Players:GetPlayerByUserId(tonumber(Item.Name)) then
						i.Visible = false
					end
					if Plr == game.Players.LocalPlayer then
						i.Visible = false
					end
				end
				
				if i.Name == 'Ban' then
					if Plr == game.Players.LocalPlayer then
						i.Visible = false
					end
				end
	
				i.MouseEnter:Connect(function()
					TweenService:Create(i, Animations.Fast, { BackgroundColor3 = Color3.fromRGB(22, 22, 22) }):Play()
					TweenService:Create(i.Icon.Scale, Animations.Fast, { Scale = 1.1 }):Play()
				end)
	
				i.MouseLeave:Connect(function()
					TweenService:Create(i, Animations.Fast, { BackgroundColor3 = Color3.fromRGB(25, 25, 25) }):Play()
					TweenService:Create(i.Icon.Scale, Animations.Fast, { Scale = 1 }):Play()
				end)
	
				i.MouseButton1Down:Connect(function()
					TweenService:Create(i, Animations.Fast, { BackgroundColor3 = Color3.fromRGB(40, 40, 40) }):Play()
					TweenService:Create(i.Icon.Scale, Animations.Fast, { Scale = 0.8 }):Play()
				end)
	
				i.MouseButton1Up:Connect(function()
					TweenService:Create(i, Animations.Fast, { BackgroundColor3 = Color3.fromRGB(25, 25, 25) }):Play()
					TweenService:Create(i.Icon.Scale, Animations.Fast, { Scale = 1 }):Play()
				end)
				
				i.MouseButton1Click:Connect(function()
					if i.Name == 'Kick' then
						Remotes.Actions.Kick:FireServer(game.Players:GetPlayerByUserId(tonumber(Item.Name)))
					end
				end)
	
			end
		end
		
		TweenService:Create(Item, Animations.Smooth, { Size = UDim2.new(1, 5, 0, 65) }):Play()
		
		Item.Interactable = true
		Item.Visible = true
		
	end
	
	local function LoadAllPlayers()
	
		--// Delete previous list
		for _, i in pairs(Plrs.scroll.display.scroll:GetChildren()) do
			if i:HasTag("OrbitPlayerItem") then
				i:Destroy()
			end
		end
	
		--// Load new list
	
		local Server = Players:GetPlayers()
		for _, Plr in pairs(Server) do
			if not Plr then continue end
			if Plr and typeof(Plr) ~= "Instance" then continue end
			if Plr and typeof(Plr) == "Instance" and Plr:IsA("Player") == false then continue end
			if Plr and not Plr.UserId then continue end
			
			AddPlayer(Plr)
			task.wait(.005)
		end
	
	end
	
	local function RemovePlayer(Player: Player)
		task.spawn(function()
			for _, i in pairs(Plrs.scroll.display.scroll:GetChildren()) do
				pcall(function()
					if i:HasTag("OrbitPlayerItem") and i:IsA("ImageButton") and i:GetAttribute("UserId") == Player.UserId then
	
						TweenService:Create(i, Animations.Smooth, { Size = UDim2.new(0, 0, 0, 0) }):Play()
						task.wait(Animations.Smooth.Time)
						i:Destroy()
	
					end
				end)
			end
		end)
	end
	
	local Filter = Plrs.scroll.filter
	local Offline = Filter.offline
	local Dropdown = Offline.Dropdown
	
	function ToggleFilter(Filter)
		for a,b in pairs(Filter.Parent:GetChildren()) do
			if b:IsA("ImageButton") then
				if b.Name ~= Filter.Name then
					TweenService:Create(b, Animations.Smooth, {
						BackgroundTransparency = 1
					}):Play()
				else
					TweenService:Create(b, Animations.Smooth, {
						BackgroundTransparency = 0
					}):Play()
				end
			end
		end
	end
	
	Filter.categories.everyone.MouseButton1Click:Connect(function()
		ToggleFilter(Filter.categories.everyone)
		LoadAllPlayers()
	end)
	
	Filter.categories.staff_members.MouseButton1Click:Connect(function()
		ToggleFilter(Filter.categories.staff_members)
		
		for _, i in pairs(Plrs.scroll.display.scroll:GetChildren()) do
			if i:HasTag("OrbitPlayerItem") then
				i:Destroy()
			end
		end
		
		local Server = Players:GetPlayers()
		local Admins = {}
		for _, i in ipairs(Server) do
			if Remotes.Retrieving.RetrievePlayerAuth:InvokeServer(i) == true then
				table.insert(Admins, i)
			end
		end
		
		for _, Plr in pairs(Admins) do
			AddPlayer(Plr)
		end
	end)
		
	function ToggleDropdown(state)
		if state then
			Plrs.scroll.ScrollingEnabled = false
			TweenService:Create(Plrs.scroll, Animations.Smooth, { CanvasPosition = Vector2.new(0, 0) }):Play()
			
			TweenService:Create(Plrs.scroll.Util.Cancellation, Animations.Smooth, { BackgroundTransparency = 0.5 }):Play()
			TweenService:Create(Dropdown.Main.Content, Animations.Smooth, { Position = UDim2.new(0.5, 0, 0, -18), AnchorPoint = Vector2.new(0.5, 0), GroupTransparency = 0 }):Play()
		else
			Plrs.scroll.ScrollingEnabled = true
			
			TweenService:Create(Plrs.scroll.Util.Cancellation, Animations.Smooth, { BackgroundTransparency = 1 }):Play()
			TweenService:Create(Dropdown.Main.Content, Animations.Smooth, { Position = UDim2.new(0.5, 0, 0, 0), AnchorPoint = Vector2.new(0.5, 1), GroupTransparency = 1 }):Play()
		end
	end
	
	Dropdown.Main.Content.result.MouseEnter:Connect(function()
		TweenService:Create(Dropdown.Main.Content.result, Animations.Smooth, { BackgroundTransparency = 0.5 }):Play()
	end)
	
	Dropdown.Main.Content.result.MouseLeave:Connect(function()
		TweenService:Create(Dropdown.Main.Content.result, Animations.Smooth, { BackgroundTransparency = 1 }):Play()
	end)
	
	Dropdown.Main.Content.result.MouseButton1Down:Connect(function()
		TweenService:Create(Dropdown.Main.Content.result, Animations.Smooth, { BackgroundTransparency = 0.7 }):Play()
	end)
	
	Dropdown.Main.Content.result.MouseButton1Up:Connect(function()
		TweenService:Create(Dropdown.Main.Content.result, Animations.Smooth, { BackgroundTransparency = 1 }):Play()
	end)
	
	Offline.textbox:GetPropertyChangedSignal("Text"):Connect(function()
		local inputText = Offline.textbox.Text
		
		if Offline.icon:GetAttribute("isToggled") == true then
			if inputText:len() >= 1 then
				local user = nil
				for _, plr in ipairs(Players:GetPlayers()) do
					if string.lower(plr.Name) == string.lower(inputText) or string.lower(plr.DisplayName) == string.lower(inputText) then
						user = plr
						break
					end
				end
	
				if user then
					ToggleDropdown(true)
	
					Dropdown.Main.Content.result.Information.Username.Text = "@" .. user.Name
					Dropdown.Main.Content.result.Information.Display.Text = user.DisplayName
					Dropdown.Main.Content.result.Thumbnail.Image = Utilities.GetThumbnailFromUserId(Utilities, user.UserId)
					
					Dropdown.Main.Content.result.MouseButton1Click:Connect(function()
						Modals.Profile(true, user.UserId)
					end)
				else
					ToggleDropdown(false)
				end
			else
				ToggleDropdown(false)
			end
	
		else
			if inputText:len() >= 5 then
				local success, userId = pcall(function()
					return Players:GetUserIdFromNameAsync(inputText)
				end)
	
				if success and userId then
					local info = UserService:GetUserInfosByUserIdsAsync({ userId })[1]
					local username = Players:GetNameFromUserIdAsync(userId)
					if not game.Players:FindFirstChild(username) then return end
					
					if info and username then
						ToggleDropdown(true)
						Dropdown.Main.Content.result.Information.Username.Text = "@" .. username
						Dropdown.Main.Content.result.Information.Display.Text = info.DisplayName
						Dropdown.Main.Content.result.Thumbnail.Image = Utilities.GetThumbnailFromUserId(Utilities, userId)
	
						Dropdown.Main.Content.result.MouseButton1Click:Connect(function()
							Modals.Profile(true, userId)
						end)
					end
				else
					ToggleDropdown(false)
				end
			else
				ToggleDropdown(false)
			end
		end
	end)
	
	LoadAllPlayers()
	
	Players.PlayerAdded:Connect(function(Plr)
		AddPlayer(Plr)
	end)
	
	Players.PlayerRemoving:Connect(function(Plr)
		RemovePlayer(Plr)
	end)
end;
task.spawn(C_4e1);
-- StarterGui.Orbit.Main.panel.content.screen.Screen.Network
local function C_4e2()
local script = G2L["4e2"];
	--// Dependances
	local Players = game:GetService("Players")
	local RepStorage = game:GetService("ReplicatedStorage")
	local TweenService = game:GetService("TweenService")
	local UserInputService = game:GetService("UserInputService")
	local UserService = game:GetService("UserService")
	local LogService = game:GetService("LogService")
	
	local Storage = RepStorage:WaitForChild("OrbitStorage")
	local Assets = Storage.Assets
	local Remotes = Storage.Events
	
	local TopbarService = require(Storage.Modules.Icon)
	
	local Client = Players.LocalPlayer
	local UI = Client.PlayerGui:WaitForChild("Orbit")
	
	local Camera = game.Workspace.CurrentCamera
	local Mouse = Client:GetMouse()
	local Viewport = Camera.ViewportSize
	
	local Interface = require(Storage.Modules.Interface)
	local Modals = require(Storage.Modules.Modals)
	
	local Main = UI.Main
	local Controls = Main.panel.controls
	local Topbar = Main.panel.topbar
	local Container = UI.Main.panel.content
	local Screen = Container.screen
	local Navigation = Container.bar
	local ModalsFrame = UI.Modals
	
	local Network = Screen.network
	
	local Notifications = require(Storage.Modules.Notifications)
	local Utilities = require(Storage.Modules.Utilities)
	local Animations = require(Storage.Modules.Directory.Animations)
	
	local role = Remotes.Retrieving.RetrievePlayerRoleTable:InvokeServer(Client)
	
	if not role then
		script.Disabled = true
	end
	
	function update()
		local data = Remotes.Retrieving.RetrieveServers:InvokeServer()
		
		-- clear networks
		for i, v in Network.scroll.display.scroll:GetChildren() do
			if v:IsA("ImageButton") then
				v:Destroy()
			end
		end
		
		-- populate
		for i, v in data do
			if typeof(v) == 'table' and v["code"] then
				local x = Network.scroll.display.scroll.List.item:Clone()
				x.Name = v["code"]
				x.Information.JobID.Text = v["jobid"] ~= "" and v["jobid"] or "nil"
				
				local formattedCode = string.format("%s-%s", string.sub(v["code"], 1, 3), string.sub(v["code"], 4, -1))
				
				x.Information.Header.Text = "Server "..formattedCode
				for _, y in v["players"] do
					local z = x.involved.list.user:Clone()
					z.Image = Players:GetUserThumbnailAsync(y.id, Enum.ThumbnailType.HeadShot, Enum.ThumbnailSize.Size420x420)
					z.Parent = x.involved
				end
				if v["layoutOverride"] then
					x.LayoutOrder = v["layoutOverride"]
				end
				x.Parent = Network.scroll.display.scroll
				
				-- button presses
				x.Actions.Shutdown.MouseButton1Click:Connect(function()
					--Remotes.Networking.ShutdownRemoteServer:FireServer(v["code"])
					local y = Modals.Confirmation(true, {header="Shutdown "..formattedCode.."?", description="This action is irreversible; every player in the target server will be kicked."})
					if y then
						Modals.Progress(true, "Shutting down "..formattedCode.."..")
						task.wait(.5)
						Remotes.Networking.ShutdownRemoteServer:FireServer(v["code"])
						Modals.Progress(false)
					end
				end)
				
				x.Actions.Manage.MouseButton1Click:Connect(function()
					Modals.ServerManagment(true, v["code"])
				end)
			else
				warn("invalid layout..?")
				print(v)
			end
		end
	end
	
	update()
	Network.scroll.filter.categories.refresh.MouseButton1Click:Connect(update)
	
	Network.scroll.filter.offline.textbox.FocusLost:Connect(function()
		local text:string = Network.scroll.filter.offline.textbox.Text -- either server code or jobid..
		local data = Remotes.Retrieving.RetrieveServers:InvokeServer()
		
		text = text:upper()
		
		-- first check if its a server code..
		-- remove any - from the text
		local serverID_Text = text:gsub("%-", "")
		local serverCode = nil
		for _, entry in data do
			if entry["code"] == serverID_Text then
				serverCode = entry
			end
		end
		
		if serverCode then
			-- its a server code! open managment.
			Modals.ServerManagment(true, serverCode["code"])
		else
			-- its not a server code, possibly a job id?
			local jobID_Text = text
			local jobID = nil
			for _, entry in data do
				if entry["jobid"] == jobID_Text then
					jobID = entry
				end
			end
			
			if jobID then
				-- its a job id! open managment with its code
				Modals.ServerManagment(true, jobID["code"])
			else
				-- invalid
				Notifications:PromptNotification({
					Header = "Invalid Server",
					Description = "No server has been found with this Job ID/Server Code.",
					Icon = "rbxassetid://11963348339",
				})
			end
		end
	end)
end;
task.spawn(C_4e2);

return G2L["1"], require;
